// BEFORE (causes hydration mismatch)
export default function Page() {
  return <p>Time: {Date.now()}</p>
}

// AFTER (client-only rendering)
'use client';
import { useState, useEffect } from 'react';

export default function Page() {
  const [time, setTime] = useState<number | null>(null);
  useEffect(() => setTime(Date.now()), []);
  return <p>Time: {time ?? 'Loading...'}</p>
}

// Add 'use client' at the very top of the file:
'use client';

import { useState } from 'react';

export default function Counter() {
  const [count, setCount] = useState(0);
  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}

// BEFORE (wrong - passing handler from server)
// page.tsx (Server Component)
export default function Page() {
  const handleClick = () => console.log('clicked');
  return <Button onClick={handleClick} />;  // Error!
}

// AFTER (correct - handler inside client component)
// Button.tsx
'use client';
export default function Button() {
  return <button onClick={() => console.log('clicked')}>Click</button>;
}

// Option 1: Force dynamic rendering
export const dynamic = 'force-dynamic';

// Option 2: Remove dynamic APIs and use static data
export async function generateStaticParams() {
  const posts = await getPosts();
  return posts.map(p => ({ slug: p.slug }));
}

