<div style={{ position: 'relative', width: '100%', height: '400px' }}>
  <Image src="/photo.jpg" fill alt="Photo" style={{ objectFit: 'cover' }} />
</div>

// Option 3: Import local image (auto dimensions)
import photo from './photo.jpg';
<Image src={photo} alt="Photo" />

// app/not-found.tsx
export default function NotFound() {
  return (
    <div>
      <h2>Not Found</h2>
      <p>Could not find the requested resource</p>
    </div>
  );
}

// In a page/layout:
import { notFound } from 'next/navigation';

export default async function Page({ params }) {
  const post = await getPost(params.id);
  if (!post) notFound();
  return <Article post={post} />;
}

// middleware.ts (at project root or src/)
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function middleware(request: NextRequest) {
  return NextResponse.next();
}

export const config = {
  matcher: ['/dashboard/:path*', '/api/:path*'],
};

// App Router route handler (app/api/users/route.ts):
import { NextResponse } from 'next/server';

export async function GET() {
  try {
    const users = await getUsers();
    return NextResponse.json(users);
  } catch (error) {
    return NextResponse.json(
      { error: 'Failed to fetch users' },
      { status: 500 }
    );
  }
}

// Option 1: Inline server action
export default function Form() {
  async function submitForm(formData: FormData) {
    'use server';
    const name = formData.get('name');
    await saveToDb(name);
  }
  return <form action={submitForm}>...</form>;
}

// Option 2: Separate file (app/actions.ts)
'use server';

export async function submitForm(formData: FormData) {
  const name = formData.get('name');
  await saveToDb(name);
}

// Add error handling to data fetching:
export default async function Page() {
  try {
    const data = await fetchData();
    if (!data) return <div>No data available</div>;
    return <Content data={data} />;
  } catch (error) {
    return <div>Failed to load page</div>;
  }
}

// Or skip prerendering for this page:
export const dynamic = 'force-dynamic';

// Suppress warning for known mismatches:
<html suppressHydrationWarning>
  <body suppressHydrationWarning>
    {children}
  </body>
</html>

// For styled-components, add the compiler config:
// next.config.js
module.exports = {
  compiler: { styledComponents: true },
};

// Use local fonts instead of Google Fonts:
import localFont from 'next/font/local';

const myFont = localFont({
  src: './fonts/MyFont.woff2',
  display: 'swap',
});

export default function Layout({ children }) {
  return <div className={myFont.className}>{children}</div>;
}

import { Suspense } from 'react';
import { SearchResults } from './SearchResults';

// Wrap the dynamic component:
export default function Page() {
  return (
    <Suspense fallback={<div>Loading...</div>}>
      <SearchResults />
    </Suspense>
  );
}

// SearchResults.tsx
'use client';
import { useSearchParams } from 'next/navigation';
export function SearchResults() {
  const params = useSearchParams();
  return <div>Query: {params.get('q')}</div>;
}

// page.tsx (Server Component - no 'use client')
import { ClientForm } from './ClientForm';

export const metadata = {
  title: 'My Page',
  description: 'Page description',
};

export default function Page() {
  return <ClientForm />;  // interactive part is a Client Component
}

// ClientForm.tsx
'use client';
export function ClientForm() {
  const [value, setValue] = useState('');
  return <input value={value} onChange={e => setValue(e.target.value)} />;
}
